const IsWinner = (gameBoard, currentMove, currentPlayer) => {
  let boar = [...gameBoard];
  boar[currentMove] = currentPlayer;
  const winLines = [[0,1,2,3], [4,5,6,7], /* ... */, [3,6,9,12]];
  for (let i = 0; i < winLines.length; i++) {
    const [c1, c2, c3, c4] = winLines[i];
    if (boar[c1] > 0 && boar[c1] === boar[c2] &&
        boar[c2] === boar[c3] && boar[c3] === boar[c4]) {
      return true;
    }
  }
  return false;
};
